function generateSelectors(paths) {
  return paths.map((path) => {
    path = path.replace(/^\/|\/$/g, "");
    if (path.includes("*")) {
      if (path.length == 1) {
        return [];
      } else if (!path.endsWith("*")) {
        return [];
      } else {
        return [`.nav-file-title[data-path^="${path.replace(/.$/, "")}"]`];
      }
    } else {
      return [
        `.nav-folder-title[data-path="${path}"]`,
        `.nav-folder-title[data-path^="${path}/"]`,
        `.nav-file-title[data-path="${path}"]`,
        `.nav-file-title[data-path^="${path}."]`,
        `.nav-file-title[data-path^="${path}/"]`
      ];
    }
  }).flat().join(", ");
}
function notesSelectors(paths) {
  return paths.map((path) => {
    path = path.replace(/^\/|\/$/g, "");
    if (path.includes("*")) {
      if (path.length == 1) {
        return [];
      } else if (!path.endsWith("*")) {
        return [];
      } else {
        return [`.nav-file-title[data-path^="${path.replace(/.$/, "")}"]`];
      }
    } else {
      return [
        `.nav-file-title[data-path="${path}"]`,
        `.nav-file-title[data-path^="${path}."]`
      ];
    }
  }).flat().join(", ");
}
