// src/commands.ts
var import_obsidian4 = require("obsidian");
function registerCommands(plugin) {
  plugin.addCommand({
    id: "toggle-configured-files-visibility",
    name: "Toggle Configured Files Visibility",
    callback: () => {
      if (!plugin.settings.passwordHash) {
        new import_obsidian4.Notice("Please set a password first.");
        return;
      }
      const promptForPassword = async () => {
        plugin.handlePasswordPrompt(async (password) => {
          if (await plugin.verifyPassword(password)) {
            toggleConfiguredFoldersVisibility(plugin);
            updateRibbonIcon(plugin);
          } else {
            plugin.showIncorrectPasswordDialog(promptForPassword);
          }
        });
      };
      promptForPassword();
    }
  });
  plugin.addCommand({
    id: "show-specified-file",
    name: "Show Specified File",
    callback: () => {
      if (!plugin.settings.passwordHash) {
        new import_obsidian4.Notice("Please set a password first.");
        return;
      }
      const promptForPassword = async () => {
        plugin.handlePasswordPrompt(async (password) => {
          if (await plugin.verifyPassword(password)) {
            promptForFilePath(plugin, (filePath) => {
              if (filePath) {
                showSpecifiedFile(plugin, filePath);
                updateRibbonIcon(plugin);
              }
            });
          } else {
            plugin.showIncorrectPasswordDialog(promptForPassword);
          }
        });
      };
      promptForPassword();
    }
  });
  plugin.addCommand({
    id: "show-all-configured-files",
    name: "Show all configured files",
    callback: () => plugin.handlePasswordPrompt(async (password) => {
      if (await plugin.verifyPassword(password)) {
        await showAllConfiguredFiles(plugin);
        updateRibbonIcon(plugin);
      } else {
        plugin.showIncorrectPasswordDialog(() => plugin.handlePasswordPrompt(async (password2) => {
          if (await plugin.verifyPassword(password2)) {
            await showAllConfiguredFiles(plugin);
            updateRibbonIcon(plugin);
          }
        }));
      }
    })
  });
  plugin.addCommand({
    id: "hide-all-configured-files",
    name: "Hide all configured files",
    callback: () => plugin.handlePasswordPrompt(async (password) => {
      if (await plugin.verifyPassword(password)) {
        await hideAllConfiguredFiles(plugin);
        updateRibbonIcon(plugin);
      } else {
        plugin.showIncorrectPasswordDialog(() => plugin.handlePasswordPrompt(async (password2) => {
          if (await plugin.verifyPassword(password2)) {
            await hideAllConfiguredFiles(plugin);
            updateRibbonIcon(plugin);
          }
        }));
      }
    })
  });
  plugin.addCommand({
    id: "create-folder",
    name: "Create folder",
    callback: () => createFolder()
  });
}
var CreateFolderModal = class extends import_obsidian4.Modal {
  constructor(app) {
    super(app);
  }
  onOpen() {
    const { contentEl } = this;
    contentEl.createEl("h2", { text: "Enter Folder Name" });
    const inputEl = contentEl.createEl("input", { type: "text", cls: "peekaboo-single-line-input-box" });
    inputEl.addEventListener("input", (e) => {
      this.folderName = e.target.value;
    });
    inputEl.addEventListener("keypress", (e) => {
      if (e.key === "Enter") {
        this.resolve(this.folderName);
        this.close();
      }
    });
    const buttonContainer = contentEl.createDiv({ cls: "peekaboo-single-line-button-container" });
    buttonContainer.createEl("button", { text: "Create", cls: "peekaboo-single-line-button" }).addEventListener("click", () => {
      this.resolve(this.folderName);
      this.close();
    });
    buttonContainer.createEl("button", { text: "Cancel", cls: "peekaboo-single-line-button" }).addEventListener("click", () => {
      this.resolve(null);
      this.close();
    });
  }
  onClose() {
    const { contentEl } = this;
    contentEl.empty();
  }
  open() {
    return new Promise((resolve) => {
      this.resolve = resolve;
      super.open();
    });
  }
};
async function createFolder() {
  const folderName = await new CreateFolderModal(this.app).open();
  if (folderName) {
    try {
      await this.app.vault.createFolder(folderName);
      new import_obsidian4.Notice(`Folder '${folderName}' created.`);
    } catch (error) {
      new import_obsidian4.Notice(`Failed to create folder '${folderName}': ${error.message}`);
    }
  }
}

// src/main.ts
var Peekaboo = class extends import_obsidian5.Plugin {
  async onload() {
    console.log("Loading Peekaboo plugin");
    await this.loadSettings();
    this.addSettingTab(new PeekabooSettingTab(this.app, this));
    registerCommands(this);
    this.styleEl = document.createElement("style");
    document.head.appendChild(this.styleEl);
    this.applyHiddenFolders();
    updateRibbonIcon(this);
  }
  onunload() {
    document.head.removeChild(this.styleEl);
    if (this.ribbonIconEl) {
      this.ribbonIconEl.remove();
    }
  }
  async loadSettings() {
    this.settings = await loadSettings(this);
  }
  async saveSettings() {
    await saveSettings(this);
  }
  applyHiddenFolders() {
    applyHiddenFolders(this);
  }
  handlePasswordPrompt(callback) {
    const promptForPassword = () => {
      this.promptForPassword(async (password) => {
        if (await this.verifyPassword(password)) {
          callback(password);
        } else {
          this.showIncorrectPasswordDialog(promptForPassword);
        }
      });
    };
    promptForPassword();
  }
  promptForPassword(callback) {
    const modal = new PasswordPromptModal(this.app, callback);
    modal.open();
  }
  showIncorrectPasswordDialog(callback) {
    const modal = new IncorrectPasswordModal(this.app, callback);
    modal.open();
  }
  async verifyPassword(password) {
    return verifyPassword(password, this.settings.passwordHash);
  }
};
